export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCellKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const candidates = new Map<string, { cell: Cell; liveNeighbors: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor[0], neighbor[1]);
      const previous = candidates.get(k)?.liveNeighbors ?? 0;
      candidates.set(k, { cell: neighbor, liveNeighbors: previous + 1 });
